async (params, browser) => {
  // Open Threads home feed
  await browser.open('https://www.threads.net/')

  // Wait for feed to load
  await browser.waitForSelector('[class*=\'ThreadItem\'], article, div[role=\'article\'], [data-pressable-container=\'true\']', 15000)

  // Let initial posts render
  await browser.wait(3000)

  // Scroll to load more posts
  await browser.scroll({ direction: 'down', amount: 2000 })

  // Wait for posts to load
  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  // Wait for more posts
  await browser.wait(2000)

  // Scroll for more posts
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

