mage = imgEl ? imgEl.src : ''; const avatarEl = el.querySelector('[class*="avatar"] img, img[alt*="profile"]'); const avatar = avatarEl ? avatarEl.src : ''; posts.push({ author: author, author_url: authorUrl, avatar: avatar, content: content, likes: likes, replies: replies, timestamp: timestamp, image: image, post_url: postUrl }); } return { post_count: posts.length, posts: posts }`)

